              "code": "# Default arguments and keyword arguments for DBA tools\ndef query_top_queries(instance, top_n=10, order_by=\"cpu\", min_executions=100):\n    \"\"\"Simulate querying top resource-consuming queries.\"\"\"\n    # In production: pyodbc query against sys.dm_exec_query_stats\n    print(f\"Instance: {instance}\")\n    print(f\"Top {top_n} queries by {order_by} (min {min_executions} executions)\")\n    return f\"SELECT TOP {top_n} * FROM sys.dm_exec_query_stats WHERE execution_count >= {min_executions} ORDER BY total_{order_by}_time DESC\"\n\n# Different calling patterns\nprint(\"=== Generated Queries ===\\n\")\nsql1 = query_top_queries(\"PROD-SQL-01\")\nprint(f\"SQL: {sql1}\\n\")\n\nsql2 = query_top_queries(\"PROD-SQL-02\", top_n=5, order_by=\"elapsed\")\nprint(f\"SQL: {sql2}\\n\")\n\nsql3 = query_top_queries(\"DEV-SQL-01\", order_by=\"logical_reads\", min_executions=10)\nprint(f\"SQL: {sql3}\")"
