              "name": "Maintenance Automation",
              "code": "# Automated index maintenance decision engine\ndef analyze_indexes(index_data):\n    \"\"\"Analyze indexes and generate maintenance commands.\"\"\"\n    commands = []\n    for idx in index_data:\n        if idx['fragmentation'] > 30 and idx['page_count'] > 1000:\n            cmd = f\"ALTER INDEX [{idx['index_name']}] ON [{idx['schema']}].[{idx['table']}] REBUILD WITH (ONLINE = ON)\"\n            commands.append({\"action\": \"REBUILD\", \"command\": cmd, \"index\": idx})\n        elif idx['fragmentation'] > 10 and idx['page_count'] > 1000:\n            cmd = f\"ALTER INDEX [{idx['index_name']}] ON [{idx['schema']}].[{idx['table']}] REORGANIZE\"\n            commands.append({\"action\": \"REORGANIZE\", \"command\": cmd, \"index\": idx})\n    return commands\n\nindexes = [\n    {\"schema\": \"dbo\", \"table\": \"Orders\",     \"index_name\": \"IX_OrderDate\",  \"fragmentation\": 45.2, \"page_count\": 15000},\n    {\"schema\": \"dbo\", \"table\": \"OrderItems\", \"index_name\": \"IX_ProductID\",  \"fragmentation\": 8.1,  \"page_count\": 8000},\n    {\"schema\": \"dbo\", \"table\": \"Customers\",  \"index_name\": \"IX_LastName\",   \"fragmentation\": 32.5, \"page_count\": 3200},\n    {\"schema\": \"dbo\", \"table\": \"Products\",   \"index_name\": \"PK_Products\",   \"fragmentation\": 67.8, \"page_count\": 500},\n    {\"schema\": \"dbo\", \"table\": \"Inventory\",  \"index_name\": \"IX_Warehouse\",  \"fragmentation\": 22.1, \"page_count\": 12000},\n]\n\ncommands = analyze_indexes(indexes)\n\nprint(\"Index Maintenance Plan:\")\nprint(\"=\" * 60)\nprint(f\"Indexes analyzed: {len(indexes)}\")\nprint(f\"Actions needed:   {len(commands)}\")\nprint()\nfor cmd in commands:\n    idx = cmd['index']\n    print(f\"  {cmd['action']}: {idx['table']}.{idx['index_name']} ({idx['fragmentation']:.1f}% frag)\")\n    print(f\"    {cmd['command'][:70]}...\")\n    print()"
