              "name": "DataFrame Analysis",
              "code": "import pandas as pd\nimport numpy as np\n\n# Simulating sys.dm_exec_query_stats output as a DataFrame\ndata = {\n    \"query_hash\": [\"0x1A2B\", \"0x3C4D\", \"0x5E6F\", \"0x7A8B\", \"0x9C0D\", \"0xEF12\", \"0x3456\", \"0x7890\"],\n    \"execution_count\": [15420, 8930, 45200, 2100, 67800, 1200, 34000, 5600],\n    \"total_cpu_ms\": [3782460, 16247150, 547420, 11403420, 257580, 9840000, 1020000, 4480000],\n    \"total_reads\": [19275000, 401850000, 3842000, 268800000, 813600, 156000000, 10200000, 78400000],\n    \"total_elapsed_ms\": [4625400, 21890000, 612000, 15200000, 340000, 12500000, 1500000, 6720000],\n}\n\ndf = pd.DataFrame(data)\n\n# Calculate per-execution averages\ndf['avg_cpu_ms'] = df['total_cpu_ms'] / df['execution_count']\ndf['avg_reads'] = df['total_reads'] / df['execution_count']\ndf['avg_elapsed_ms'] = df['total_elapsed_ms'] / df['execution_count']\n\nprint(\"Top Queries by Average CPU Time:\")\nprint(df.sort_values('avg_cpu_ms', ascending=False)[['query_hash', 'execution_count', 'avg_cpu_ms', 'avg_reads']].head(5).to_string(index=False))\n\nprint(f\"\\nSummary Statistics:\")\nprint(f\"  Total queries tracked: {len(df)}\")\nprint(f\"  Total executions: {df['execution_count'].sum():,}\")\nprint(f\"  Highest avg CPU: {df['avg_cpu_ms'].max():.0f} ms\")\nprint(f\"  Queries > 1000ms avg: {len(df[df['avg_cpu_ms'] > 1000])}\")"
