              "name": "Data Cleaning",
              "code": "import pandas as pd\nimport numpy as np\n\n# Simulating messy monitoring data that needs cleaning\nraw_data = {\n    \"timestamp\": [\"2024-06-15 08:00\", \"2024-06-15 08:05\", \"2024-06-15 08:10\", \n                  \"2024-06-15 08:15\", \"2024-06-15 08:20\", \"2024-06-15 08:25\",\n                  \"2024-06-15 08:30\", \"2024-06-15 08:35\"],\n    \"cpu_percent\": [45, 52, np.nan, 48, 999, 55, 51, np.nan],\n    \"memory_percent\": [72, 75, 74, np.nan, 76, 78, 77, 79],\n    \"batch_requests\": [12000, 13500, 12800, 14000, -100, 13200, 12900, 13800],\n}\n\ndf = pd.DataFrame(raw_data)\nprint(\"Raw Data (with issues):\")\nprint(df.to_string(index=False))\n\n# Clean the data\nprint(\"\\nCleaning steps:\")\n\n# 1. Replace impossible values with NaN\ndf.loc[df['cpu_percent'] > 100, 'cpu_percent'] = np.nan\ndf.loc[df['batch_requests'] < 0, 'batch_requests'] = np.nan\nprint(f\"  1. Replaced {df['cpu_percent'].isna().sum()} invalid CPU values\")\nprint(f\"     Replaced {df['batch_requests'].isna().sum()} invalid batch values\")\n\n# 2. Fill NaN with interpolation\ndf['cpu_percent'] = df['cpu_percent'].interpolate()\ndf['memory_percent'] = df['memory_percent'].interpolate()\ndf['batch_requests'] = df['batch_requests'].interpolate()\nprint(\"  2. Interpolated missing values\")\n\nprint(\"\\nCleaned Data:\")\nprint(df.to_string(index=False))\nprint(f\"\\nReady for ML: {df.isna().sum().sum()} remaining nulls\")"
