              "name": "Chat Pattern",
              "code": "# Simulating a multi-turn chat for DBA troubleshooting\n# Pattern used with OpenAI/Azure OpenAI chat completions API\n\nclass DBAChat:\n    \"\"\"Simulates a multi-turn DBA troubleshooting chat.\"\"\"\n    \n    def __init__(self):\n        self.history = []\n        self.system_prompt = \"You are a SQL Server DBA expert. Help diagnose performance issues.\"\n    \n    def add_message(self, role, content):\n        self.history.append({\"role\": role, \"content\": content})\n    \n    def get_response(self, user_message):\n        \"\"\"Simulate AI response based on context.\"\"\"\n        self.add_message(\"user\", user_message)\n        \n        # Simple pattern matching for demo\n        if \"cpu\" in user_message.lower() and \"high\" in user_message.lower():\n            response = \"High CPU on SQL Server is commonly caused by:\\n1. Missing indexes (table scans)\\n2. Excessive parallelism (check MAXDOP)\\n3. Query recompilations\\n4. Implicit conversions\\n\\nRun: SELECT * FROM sys.dm_exec_query_stats ORDER BY total_worker_time DESC\"\n        elif \"wait\" in user_message.lower():\n            response = \"To analyze waits, run:\\nSELECT wait_type, wait_time_ms/1000.0 AS wait_sec\\nFROM sys.dm_os_wait_stats\\nWHERE wait_type NOT IN ('WAITFOR','SLEEP_TASK')\\nORDER BY wait_time_ms DESC\"\n        elif \"next\" in user_message.lower() or \"then\" in user_message.lower():\n            response = \"Based on the wait stats, if PAGEIOLATCH is top:\\n- Check disk latency (sys.dm_io_virtual_file_stats)\\n- Look for missing indexes\\n- Consider adding memory to increase buffer pool\"\n        else:\n            response = \"Could you provide more details about the symptoms?\"\n        \n        self.add_message(\"assistant\", response)\n        return response\n\n# Simulate a troubleshooting session\nchat = DBAChat()\nconversation = [\n    \"My production SQL Server has high CPU since this morning\",\n    \"The top wait type is PAGEIOLATCH_SH\",\n    \"What should I check next?\",\n]\n\nprint(\"DBA Troubleshooting Chat Session:\")\nprint(\"=\" * 50)\nfor msg in conversation:\n    print(f\"\\nDBA: {msg}\")\n    response = chat.get_response(msg)\n    print(f\"AI:  {response}\")\n\nprint(f\"\\n(Chat history: {len(chat.history)} messages)\")"
